-- Fix ID 3527: "ZAP (13 - Rua Vergueiro- Condomínio Edifício Vergueiro"
UPDATE establishments SET address = 'Rua Vergueiro', complement = 'Condomínio Edifício Vergueiro', addressNumber = '13' WHERE id = 3527;

-- Fix ID 3529: "Centro Cultural 01504-000 - Rua Vergueiro"
UPDATE establishments SET address = 'Rua Vergueiro', complement = 'Centro Cultural São Paulo' WHERE id = 3529;

-- Fix ID 4112: "Pc. Dom José GasparAB" 
UPDATE establishments SET address = 'Praça Dom José Gaspar' WHERE id = 4112;

-- Verificar contagem final
SELECT COUNT(*) as total, 
  SUM(CASE WHEN status = 'active' THEN 1 ELSE 0 END) as ativos,
  SUM(CASE WHEN status = 'pending' THEN 1 ELSE 0 END) as pendentes,
  SUM(CASE WHEN status = 'hidden' THEN 1 ELSE 0 END) as ocultos
FROM establishments;

